% 1.4 - Velocity v(t) and Plot
m  = 5;
k  = 2000;
x0 = 0.02;

wn = sqrt(k/m);
t  = linspace(0, 5, 1000);

x = x0 * cos(wn * t);          % displacement
v = -x0 * wn * sin(wn * t);    % velocity = dx/dt

fprintf('Peak velocity = %.4f m/s\n', max(abs(v))); %[output:5958f7af]

figure(2); %[output:88ea1793]
plot(t, v, 'r-', 'LineWidth', 1.5); %[output:88ea1793]
xlabel('Time (s)'); %[output:88ea1793]
ylabel('Velocity v(t) [m/s]'); %[output:88ea1793]
title('Undamped Free Vibration — Velocity vs Time'); %[output:88ea1793]
grid on; %[output:88ea1793]

